{"command": "cd /tmp/sv-0c81929ed24844b4bb792b559276876d/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k, '-')
    av = a.get(k, '-')
    if bv != av:
        changes.append((proj, tfm, pkg, bv, av))
    else:
        unchanged.append((proj, tfm, pkg, bv))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Before':<10} {'After':<10}')
    for p, t, pkg, bv, av in changes:
        print(f'{p:<16} {t:<8} {pkg:<45} {bv:<10} {av:<10}')
else:
    print('None')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Version':<10}')
for p, t, pkg, v in unchanged:
    print(f'{p:<16} {t:<8} {pkg:<45} {v:<10}')
"
", "description": "Compare baseline vs post-conversion"}
